<template><el-card><template #header>Markdown 编译文件</template><PageToolbar><el-select v-model="selectedId"><el-option v-for="d in docs" :key="d.id" :label="d.title" :value="d.id"/></el-select><template #actions><el-button type="warning" @click="doc!.status='reviewing'">提交审核</el-button></template></PageToolbar><div class="two-col"><MarkdownPreview :content="doc?.content||''"/><el-card><template #header>结构化摘要</template><p>{{doc?.summary}}</p><el-divider/>关键规则：<el-tag v-for="r in doc?.rules" :key="r">{{r}}</el-tag><el-divider/>办理材料：<el-tag v-for="r in doc?.materials" :key="r" type="success">{{r}}</el-tag><el-divider/>办理流程：<FlowSteps :steps="doc?.flow||[]"/><el-divider/>典型问答：<p v-for="q in doc?.qa" :key="q">Q：{{q}}</p>证据锚点：<el-tag v-for="a in doc?.anchors" :key="a" type="warning">{{a}}</el-tag></el-card></div></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { markdownDocs } from '@/mock/data'; import MarkdownPreview from '@/components/MarkdownPreview.vue'; import PageToolbar from '@/components/PageToolbar.vue'; import FlowSteps from '@/components/FlowSteps.vue'; const docs=ref(JSON.parse(JSON.stringify(markdownDocs))); const selectedId=ref(docs.value[0].id); const doc=computed(()=>docs.value.find((i:any)=>i.id===selectedId.value));</script>
